# Category: serverless_security

import os
import json
import logging
import datetime
import uuid
from typing import Optional

import azure.functions as func
from azure.identity import DefaultAzureCredential, ManagedIdentityCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent


# Configuration from environment variables
STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "https://<storage-account>.blob.core.windows.net")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "https://<cosmos-account>.documents.azure.com:443/")
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "processing-results")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
EVENTGRID_TOPIC_ENDPOINT = os.environ.get("EVENTGRID_TOPIC_ENDPOINT", "https://<topic>.eastus-1.eventgrid.azure.net/api/events")
SOURCE_CONTAINER = os.environ.get("SOURCE_CONTAINER", "input-files")
PROCESSED_CONTAINER = os.environ.get("PROCESSED_CONTAINER", "processed-files")
MANAGED_IDENTITY_CLIENT_ID = os.environ.get("MANAGED_IDENTITY_CLIENT_ID", None)

app = func.FunctionApp()


def get_credential():
    """
    Get Azure credential using Managed Identity.
    Uses user-assigned managed identity if client ID is provided,
    otherwise falls back to DefaultAzureCredential (supports local dev too).
    
    SECURITY NOTE (MVP): This function uses broad permissions:
    - Storage Blob Data Contributor
    - Cosmos DB Account Contributor  
    - Event Grid Data Sender
    
    For production, follow least-privilege principle:
    - Use Storage Blob Data Reader where only read is needed
    - Use Cosmos DB custom RBAC roles scoped to specific databases/containers
    - Scope Event Grid permissions to specific topics
    - Consider separate managed identities per resource
    """
    if MANAGED_IDENTITY_CLIENT_ID:
        return ManagedIdentityCredential(client_id=MANAGED_IDENTITY_CLIENT_ID)
    return DefaultAzureCredential()


def get_blob_service_client() -> BlobServiceClient:
    """Create BlobServiceClient using Managed Identity."""
    credential = get_credential()
    return BlobServiceClient(account_url=STORAGE_ACCOUNT_URL, credential=credential)


def get_cosmos_client() -> CosmosClient:
    """Create CosmosClient using Managed Identity (AAD authentication)."""
    credential = get_credential()
    return CosmosClient(url=COSMOS_ENDPOINT, credential=credential)


def get_eventgrid_client() -> EventGridPublisherClient:
    """Create EventGridPublisherClient using Managed Identity."""
    credential = get_credential()
    return EventGridPublisherClient(endpoint=EVENTGRID_TOPIC_ENDPOINT, credential=credential)


def ensure_cosmos_resources(cosmos_client: CosmosClient):
    """Ensure Cosmos DB database and container exist."""
    database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
    container = database.create_container_if_not_exists(
        id=COSMOS_CONTAINER_NAME,
        partition_key=PartitionKey(path="/partitionKey"),
        offer_throughput=400
    )
    return database, container


def process_file_content(blob_name: str, content: bytes) -> dict:
    """
    Process the file content and return structured results.
    This is the core business logic - customize for your use case.
    """
    content_str = content.decode("utf-8", errors="replace")
    
    # Example processing: analyze file metadata and content
    lines = content_str.split("\n")
    word_count = sum(len(line.split()) for line in lines)
    
    result = {
        "id": str(uuid.uuid4()),
        "partitionKey": blob_name.split("/")[0] if "/" in blob_name else "default",
        "fileName": blob_name,
        "processedAt": datetime.datetime.utcnow().isoformat() + "Z",
        "fileSize": len(content),
        "lineCount": len(lines),
        "wordCount": word_count,
        "status": "processed",
        "summary": {
            "firstLine": lines[0][:200] if lines else "",
            "encoding": "utf-8",
        },
    }
    
    return result


def send_notification(eventgrid_client: EventGridPublisherClient, result: dict, event_type: str = "FileProcessed"):
    """Send processing result notification via Event Grid."""
    event = CloudEvent(
        source="azure-function/file-processor",
        type=f"com.mvp.fileprocessor.{event_type}",
        data={
            "fileName": result.get("fileName"),
            "fileSize": result.get("fileSize"),
            "processedAt": result.get("processedAt"),
            "status": result.get("status"),
            "resultId": result.get("id"),
            "wordCount": result.get("wordCount"),
            "lineCount": result.get("lineCount"),
        },
        subject=f"files/{result.get('fileName', 'unknown')}",
    )
    
    eventgrid_client.send([event])
    logging.info(f"Event Grid notification sent for file: {result.get('fileName')}")


def move_blob_to_processed(blob_service_client: BlobServiceClient, blob_name: str):
    """Move processed blob from source to processed container."""
    source_blob = blob_service_client.get_blob_client(SOURCE_CONTAINER, blob_name)
    dest_blob = blob_service_client.get_blob_client(PROCESSED_CONTAINER, blob_name)
    
    # Ensure processed container exists
    try:
        blob_service_client.create_container(PROCESSED_CONTAINER)
    except Exception:
        pass  # Container already exists
    
    # Copy blob to processed container
    source_url = source_blob.url
    dest_blob.start_copy_from_url(source_url)
    
    # Delete from source
    source_blob.delete_blob()
    logging.info(f"Moved blob {blob_name} to {PROCESSED_CONTAINER} container")


# --- Azure Function Triggers ---

@app.blob_trigger(
    arg_name="inputblob",
    path=f"{SOURCE_CONTAINER}/{{name}}",
    connection="AzureWebJobsStorage"
)
def blob_trigger_processor(inputblob: func.InputStream):
    """
    Blob-triggered function: automatically processes files uploaded to the input container.
    
    Trigger: New blob in SOURCE_CONTAINER
    Actions:
    1. Read and process blob content
    2. Write results to Cosmos DB
    3. Send notification via Event Grid
    4. Move blob to processed container
    """
    blob_name = inputblob.name
    # Remove container prefix if present
    if blob_name.startswith(f"{SOURCE_CONTAINER}/"):
        blob_name = blob_name[len(f"{SOURCE_CONTAINER}/"):]
    
    logging.info(f"Blob trigger fired for: {blob_name}, Size: {inputblob.length} bytes")
    
    try:
        # Read blob content
        content = inputblob.read()
        
        # Process the file
        result = process_file_content(blob_name, content)
        logging.info(f"File processed: {json.dumps(result, indent=2)}")
        
        # Write to Cosmos DB
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_resources(cosmos_client)
        container.upsert_item(result)
        logging.info(f"Result written to Cosmos DB with id: {result['id']}")
        
        # Send Event Grid notification
        try:
            eventgrid_client = get_eventgrid_client()
            send_notification(eventgrid_client, result)
        except Exception as eg_error:
            logging.warning(f"Event Grid notification failed (non-fatal): {eg_error}")
        
        # Move blob to processed container
        try:
            blob_service_client = get_blob_service_client()
            move_blob_to_processed(blob_service_client, blob_name)
        except Exception as move_error:
            logging.warning(f"Failed to move blob (non-fatal): {move_error}")
        
        logging.info(f"Successfully processed blob: {blob_name}")
        
    except Exception as e:
        logging.error(f"Error processing blob {blob_name}: {str(e)}")
        
        # Write error result to Cosmos DB
        try:
            error_result = {
                "id": str(uuid.uuid4()),
                "partitionKey": "errors",
                "fileName": blob_name,
                "processedAt": datetime.datetime.utcnow().isoformat() + "Z",
                "status": "error",
                "error": str(e),
            }
            cosmos_client = get_cosmos_client()
            _, container = ensure_cosmos_resources(cosmos_client)
            container.upsert_item(error_result)
        except Exception as cosmos_error:
            logging.error(f"Failed to write error to Cosmos DB: {cosmos_error}")
        
        # Send error notification
        try:
            eventgrid_client = get_eventgrid_client()
            send_notification(eventgrid_client, error_result, event_type="FileProcessingError")
        except Exception:
            pass
        
        raise


@app.route(route="process", methods=["POST"], auth_level=func.AuthLevel.FUNCTION)
def http_trigger_processor(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function: manually trigger processing of a specific blob.
    
    Request body:
    {
        "container": "input-files",  (optional, defaults to SOURCE_CONTAINER)
        "blobName": "path/to/file.txt"
    }
    """
    logging.info("HTTP trigger: manual file processing request")
    
    try:
        req_body = req.get_json()
    except ValueError:
        return func.HttpResponse(
            json.dumps({"error": "Invalid JSON in request body"}),
            status_code=400,
            mimetype="application/json"
        )
    
    container_name = req_body.get("container", SOURCE_CONTAINER)
    blob_name = req_body.get("blobName")
    
    if not blob_name:
        return func.HttpResponse(
            json.dumps({"error": "blobName is required"}),
            status_code=400,
            mimetype="application/json"
        )
    
    try:
        # Read blob from storage
        blob_service_client = get_blob_service_client()
        blob_client = blob_service_client.get_blob_client(container_name, blob_name)
        content = blob_client.download_blob().readall()
        
        # Process the file
        result = process_file_content(blob_name, content)
        
        # Write to Cosmos DB
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_resources(cosmos_client)
        container.upsert_item(result)
        
        # Send Event Grid notification
        try:
            eventgrid_client = get_eventgrid_client()
            send_notification(eventgrid_client, result)
        except Exception as eg_error:
            logging.warning(f"Event Grid notification failed: {eg_error}")
            result["notificationStatus"] = f"failed: {str(eg_error)}"
        
        return func.HttpResponse(
            json.dumps({"message": "File processed successfully", "result": result}),
            status_code=200,
            mimetype="application/json"
        )
        
    except Exception as e:
        logging.error(f"Error processing file {blob_name}: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": f"Processing failed: {str(e)}"}),
            status_code=500,
            mimetype="application/json"
        )


@app.route(route="results", methods=["GET"], auth_level=func.AuthLevel.FUNCTION)
def get_results(req: func.HttpRequest) -> func.HttpResponse:
    """
    HTTP-triggered function: query processing results from Cosmos DB.
    
    Query parameters:
    - status: filter by status (processed, error)
    - fileName: filter by file name
    - limit: max results (default 50)
    """
    logging.info("HTTP trigger: query results")
    
    try:
        status_filter = req.params.get("status")
        file_name_filter = req.params.get("fileName")
        limit = int(req.params.get("limit", "50"))
        
        cosmos_client = get_cosmos_client()
        _, container = ensure_cosmos_resources(cosmos_client)
        
        # Build query
        query = "SELECT * FROM c"
        conditions = []
        parameters = []
        
        if status_filter:
            conditions.append("c.status = @status")
            parameters.append({"name": "@status", "value": status_filter})
        
        if file_name_filter:
            conditions.append("c.fileName = @fileName")
            parameters.append({"name": "@fileName", "value": file_name_filter})
        
        if conditions:
            query += " WHERE " + " AND ".join(conditions)
        
        query += " ORDER BY c.processedAt DESC"
        query += f" OFFSET 0 LIMIT {limit}"
        
        items = list(container.query_items(
            query=query,
            parameters=parameters if parameters else None,
            enable_cross_partition_query=True
        ))
        
        return func.HttpResponse(
            json.dumps({"count": len(items), "results": items}, default=str),
            status_code=200,
            mimetype="application/json"
        )
        
    except Exception as e:
        logging.error(f"Error querying results: {str(e)}")
        return func.HttpResponse(
            json.dumps({"error": f"Query failed: {str(e)}"}),
            status_code=500,
            mimetype="application/json"
        )


@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health_check(req: func.HttpRequest) -> func.HttpResponse:
    """Health check endpoint that verifies connectivity to all services."""
    health = {
        "status": "healthy",
        "timestamp": datetime.datetime.utcnow().isoformat() + "Z",
        "services": {}
    }
    
    # Check Blob Storage
    try:
        blob_service_client = get_blob_service_client()
        blob_service_client.get_account_information()
        health["services"]["blobStorage"] = {"status": "connected"}
    except Exception as e:
        health["services"]["blobStorage"] = {"status": "error", "message": str(e)}
        health["status"] = "degraded"
    
    # Check Cosmos DB
    try:
        cosmos_client = get_cosmos_client()
        list(cosmos_client.list_databases())
        health["services"]["cosmosDb"] = {"status": "connected"}
    except Exception as e:
        health["services"]["cosmosDb"] = {"status": "error", "message": str(e)}
        health["status"] = "degraded"
    
    # Check Event Grid (basic client creation)
    try:
        _ = get_eventgrid_client()
        health["services"]["eventGrid"] = {"status": "client_created"}
    except Exception as e:
        health["services"]["eventGrid"] = {"status": "error", "message": str(e)}
        health["status"] = "degraded"
    
    status_code = 200 if health["status"] == "healthy" else 503
    return func.HttpResponse(
        json.dumps(health, indent=2),
        status_code=status_code,
        mimetype="application/json"
    )


@app.timer_trigger(
    schedule="0 0 */6 * * *",  # Every 6 hours
    arg_name="timer",
    run_on_startup=False
)
def batch_processor(timer: func.TimerRequest):
    """
    Timer-triggered function: periodically scans for unprocessed files.
    Runs every 6 hours as a safety net for any missed blob triggers.
    """
    if timer.past_due:
        logging.info("Timer is past due, running catch-up")
    
    logging.info("Batch processor started - scanning for unprocessed files")
    
    try:
        blob_service_client = get_blob_service_client()
        container_client = blob_service_client.get_container_client(SOURCE_CONTAINER)
        
        processed_count = 0
        error_count = 0
        
        for blob in container_client.list_blobs():
            try:
                logging.info(f"Batch processing: {blob.name}")
                
                blob_client = container_client.get_blob_client(blob.name)
                content = blob_client.download_blob().readall()
                
                result = process_file_content(blob.name, content)
                
                cosmos_client = get_cosmos_client()
                _, container = ensure_cosmos_resources(cosmos_client)
                container.upsert_item(result)
                
                try:
                    eventgrid_client = get_eventgrid_client()
                    send_notification(eventgrid_client, result, event_type="BatchFileProcessed")
                except Exception:
                    pass
                
                try:
                    move_blob_to_processed(blob_service_client, blob.name)
                except Exception:
                    pass
                
                processed_count += 1
                
            except Exception as e:
                logging.error(f"Error batch processing {blob.name}: {e}")
                error_count += 1
        
        logging.info(f"Batch processing complete. Processed: {processed_count}, Errors: {error_count}")
        
    except Exception as e:
        logging.error(f"Batch processor error: {str(e)}")